function slider() {

  const slidPrev = document.querySelector(".offer__slider-prev"),
    slider = document.querySelector(".offer__slider"),
    slidNext = document.querySelector(".offer__slider-next"),
    current = document.querySelector("#current"),
    total = document.querySelector("#total"),
    slides = document.querySelectorAll(".offer__slide"),
    slidesWrapper = document.querySelector(".offer__slider-wrapper"),
    slidesField = document.querySelector(".offer__slider-inner"),
    width = window.getComputedStyle(slidesWrapper).width;

  let indSlide = 1;
  let offset = 0;


  if (slides.length < 10) {
    total.textContent = `0${slides.length}`;
    current.textContent = `0${indSlide}`
  } else {
    total.textContent = slides.length;
    current.textContent = indSlide
  }

  slidesField.style.width = 100 * slides.length + "%";
  slidesField.style.display = "flex";
  slidesField.style.transition = '0.5s all';


  slidesWrapper.style.overflow = 'hidden'
  slides.forEach(slide => {
    slide.style.width = width;
  });

  slider.style.position = "relative";

  const indicators = document.createElement("ol"),
    dots = [];

  indicators.classList.add("carousel-indicators");
  indicators.style.cssText = `
    position: absolute;
    right: 0;
    bottom: 0;
    left: 0;
    z-index: 15;
    display: flex;
    justify-content: center;
    margin-right: 15%;
    margin-left: 15%;
    list-style: none;
`;
  slider.append(indicators);


  for (let i = 0; i < slides.length; i++) {
    const dot = document.createElement('li');
    dot.setAttribute('data-slide-to', i + 1);
    dot.style.cssText = `
    box-sizing: content-box;
    flex: 0 1 auto;
    width: 30px;
    height: 6px;
    margin-right: 3px;
    margin-left: 3px;
    cursor: pointer;
    background-color: #fff;
    background-clip: padding-box;
    border-top: 10px solid transparent;
    border-bottom: 10px solid transparent;
    opacity: .5;
    transition: opacity .6s ease;
  `;
    if (i == 0) {
      dot.style.opacity = 1;
    }
    indicators.append(dot);
    dots.push(dot);
  }

  function deleteNotDigits(str) {
    return +str.replace(/\D/g, "");
  }

  slidNext.addEventListener("click", () => {
    if (offset == deleteNotDigits(width) * (slides.length - 1)) {
      offset = 0;
    } else {
      offset += deleteNotDigits(width);
    }

    slidesField.style.transform = `translateX(-${offset}px)`;

    if (indSlide == slides.length) {
      indSlide = 1;
    } else {
      indSlide++;
    }

    if (slides.length < 10) {
      current.textContent = `0${indSlide}`;
    } else {
      current.textContent = indSlide;
    }

    dots.forEach(dot => dot.style.opacity = ".5");
    dots[indSlide - 1].style.opacity = 1;
  })

  slidPrev.addEventListener("click", () => {
    if (offset == 0) {
      offset = deleteNotDigits(width) * (slides.length - 1);
    } else {
      offset -= deleteNotDigits(width);
    }

    slidesField.style.transform = `translateX(-${offset}px)`;

    if (indSlide == 1) {
      indSlide = slides.length;
    } else {
      indSlide--;
    }

    if (slides.length < 10) {
      current.textContent = `0${indSlide}`;
    } else {
      current.textContent = indSlide;
    }

    dots.forEach(dot => dot.style.opacity = ".5");
    dots[indSlide - 1].style.opacity = 1;

  })

  dots.forEach(dot => {
    dot.addEventListener('click', (e) => {
      const slideTo = e.target.getAttribute('data-slide-to');

      indSlide = slideTo;
      offset = deleteNotDigits(width) * (slideTo - 1);

      slidesField.style.transform = `translateX(-${offset}px)`;

      if (slides.length < 10) {
        current.textContent = `0${indSlide}`;
      } else {
        current.textContent = indSlide;
      }

      dots.forEach(dot => dot.style.opacity = ".5");
      dots[indSlide - 1].style.opacity = 1;

    });
  })
}

module.exports = slider;